#!/usr/bin/env node
/**
 * patch-gradle-signing.js
 *
 * Patches android/app/build.gradle (generated by expo prebuild) to inject
 * a release signing configuration from the provided arguments.
 *
 * Usage:
 *   node scripts/patch-gradle-signing.js \
 *     --keystore /abs/path/to/netscope-release.keystore \
 *     --store-password <password> \
 *     --key-alias <alias> \
 *     --key-password <password>
 */

const fs = require('fs');
const path = require('path');

// ── Parse CLI args ────────────────────────────────────────────────────────────
const args = process.argv.slice(2);
const get = (flag) => {
  const i = args.indexOf(flag);
  return i !== -1 ? args[i + 1] : null;
};

const keystorePath  = get('--keystore');
const storePassword = get('--store-password');
const keyAlias      = get('--key-alias');
const keyPassword   = get('--key-password');

if (!keystorePath || !storePassword || !keyAlias || !keyPassword) {
  console.error('❌ Missing required arguments.');
  console.error('Usage: node patch-gradle-signing.js --keystore <path> --store-password <pw> --key-alias <alias> --key-password <pw>');
  process.exit(1);
}

const buildGradlePath = path.resolve(__dirname, '../android/app/build.gradle');

if (!fs.existsSync(buildGradlePath)) {
  console.error(`❌ build.gradle not found at: ${buildGradlePath}`);
  console.error('   Run "expo prebuild --platform android" first.');
  process.exit(1);
}

// ── Read current build.gradle ────────────────────────────────────────────────
let gradle = fs.readFileSync(buildGradlePath, 'utf8');

// ── Guard: already patched? ──────────────────────────────────────────────────
if (gradle.includes('// NETSCOPE-SIGNING-PATCH')) {
  console.log('ℹ️  build.gradle already patched with signing config. Skipping.');
  process.exit(0);
}

// ── Build the release signing config block ────────────────────────────────────
const releaseSigningBlock = `
        // NETSCOPE-SIGNING-PATCH — injected by scripts/patch-gradle-signing.js
        release {
            storeFile file("${keystorePath.replace(/\\/g, '/')}")
            storePassword "${storePassword}"
            keyAlias "${keyAlias}"
            keyPassword "${keyPassword}"
        }`;

// ── 1. Inject release signingConfig after the debug signingConfig ─────────────
//  Expo prebuild generates:
//    signingConfigs {
//        debug {
//            storeFile file('debug.keystore')
//            ...
//        }
//    }
const signingConfigsPattern = /(signingConfigs\s*\{[\s\S]*?debug\s*\{[\s\S]*?\})/;
if (!signingConfigsPattern.test(gradle)) {
  // No signingConfigs block — inject one before the buildTypes block
  const buildTypesIdx = gradle.indexOf('buildTypes {');
  if (buildTypesIdx === -1) {
    console.error('❌ Could not find "buildTypes {" in build.gradle. Unexpected format.');
    process.exit(1);
  }
  const newSigningConfigsBlock = `
    signingConfigs {
        debug {
            storeFile file('debug.keystore')
            storePassword 'android'
            keyAlias 'androiddebugkey'
            keyPassword 'android'
        }${releaseSigningBlock}
    }

    `;
  gradle = gradle.slice(0, buildTypesIdx) + newSigningConfigsBlock + gradle.slice(buildTypesIdx);
  console.log('✅ Inserted signingConfigs block (debug + release).');
} else {
  // Append release config inside the existing signingConfigs block
  gradle = gradle.replace(
    /(signingConfigs\s*\{)([\s\S]*?)(debug\s*\{[\s\S]*?\})\s*(\})/,
    (match, open, before, debugBlock, close) => {
      return `${open}${before}${debugBlock}${releaseSigningBlock}\n    ${close}`;
    },
  );
  console.log('✅ Injected release signing config into existing signingConfigs block.');
}

// ── 2. Switch release buildType from signingConfigs.debug → signingConfigs.release ──
// Expo prebuild sets the release buildType to use debug signing:
//   release {
//     signingConfig signingConfigs.debug
//     ...
//   }
const releaseBuildTypePattern = /(release\s*\{[\s\S]*?)(signingConfig\s+signingConfigs\.debug)/;
if (releaseBuildTypePattern.test(gradle)) {
  gradle = gradle.replace(releaseBuildTypePattern, (match, prefix, signingLine) => {
    return prefix + 'signingConfig signingConfigs.release';
  });
  console.log('✅ Switched release buildType to use signingConfigs.release.');
} else if (gradle.includes('signingConfig signingConfigs.debug')) {
  // Fallback: replace first occurrence inside a release block
  gradle = gradle.replace('signingConfig signingConfigs.debug', 'signingConfig signingConfigs.release');
  console.log('✅ Replaced signingConfig reference in release buildType.');
} else {
  // No existing signingConfig in release buildType — inject it
  gradle = gradle.replace(
    /(buildTypes\s*\{[\s\S]*?release\s*\{)/,
    `$1\n            signingConfig signingConfigs.release`
  );
  console.log('✅ Injected signingConfig into release buildType.');
}

// ── Write patched build.gradle ────────────────────────────────────────────────
fs.writeFileSync(buildGradlePath, gradle, 'utf8');
console.log(`✅ Patched: ${buildGradlePath}`);

// ── Print summary ─────────────────────────────────────────────────────────────
console.log('\n=== Signing Configuration ===');
console.log(`  Keystore : ${keystorePath}`);
console.log(`  Alias    : ${keyAlias}`);
console.log(`  Password : ${'*'.repeat(storePassword.length)}`);
console.log('=============================\n');
console.log('Ready to build: cd android && ./gradlew assembleRelease');
